export interface Sale {
  domain: string;
  price: number;
  priceFormatted: string;
  venue: string;
  date: string;
  source: string;
  sourceUrl: string;
  buyer: string;
  seller: string;
}

function fmt(price: number): string {
  return "$" + price.toLocaleString("en-US");
}

const HARDCODED_URLS: Record<string, string> = {
  "ai.com": "https://techcrunch.com/2023/02/07/openai-ai-com/",
  "voice.ai": "https://voice.ai",
  "x.ai": "https://x.ai",
  "open.ai": "https://openai.com",
  "data.ai": "https://www.data.ai/en/",
};

function buildSourceUrl(domain: string, source: string): string {
  const key = domain.toLowerCase();
  if ((HARDCODED_URLS as Record<string,string>)[key]) return (HARDCODED_URLS as Record<string,string>)[key];
  if (source.toLowerCase() === "namebio") {
    const name = domain.replace(/\.ai$/i, "");
    return "https://namebio.com/?s=" + encodeURIComponent(name);
  }
  return "https://www.dnjournal.com/ytd-sales-charts.htm";
}

function sale(
  domain: string,
  price: number,
  venue: string,
  date: string,
  source: string,
  buyer = "Undisclosed",
  seller = "Undisclosed",
  sourceUrl?: string
): Sale {
  const url = sourceUrl ?? buildSourceUrl(domain, source);
  return { domain, price, priceFormatted: fmt(price), venue, date, source, sourceUrl: url, buyer, seller };
}

export function domainToSlug(domain: string): string {
  return domain.toLowerCase().replace(/\./g, "-").replace(/\s+/g, "-");
}

export function slugToDomain(slug: string): string {
  return slug.replace(/-ai$/, ".ai");
}

